import{_ as t,o as a,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Blue Team Practices","description":"","frontmatter":{},"headers":[],"relativePath":"blue-team.md","filePath":"blue-team.md"}'),o={name:"blue-team.md"};function n(s,e,l,c,d,p){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="blue-team-practices" tabindex="-1">Blue Team Practices <a class="header-anchor" href="#blue-team-practices" aria-label="Permalink to &quot;Blue Team Practices&quot;">​</a></h1><p>NotTodayHoney is a detection and alerting layer. It tells you an attacker is present and records what they tried. It does not stop packets, enforce firewall rules, or protect your application from vulnerabilities.</p><p>Understanding what a honeypot is — and isn&#39;t — helps you build a security posture that actually holds.</p><h2 id="defense-in-depth" tabindex="-1">Defense in depth <a class="header-anchor" href="#defense-in-depth" aria-label="Permalink to &quot;Defense in depth&quot;">​</a></h2><p>No single tool provides complete security. Defense in depth means stacking independent layers so that the failure of any one layer does not compromise the whole system.</p><p>NotTodayHoney fits in the <strong>detection</strong> layer. It should sit alongside:</p><ul><li>An <strong>edge layer</strong> (reverse proxy, CDN, WAF) that handles TLS termination, request filtering, and IP reputation checks before traffic reaches your application</li><li>An <strong>OS/network layer</strong> that acts on blocked IPs at the infrastructure level — before your web server even starts processing a request</li><li>A <strong>hardened application layer</strong> where real admin routes require strong authentication, and attack surface is minimised</li></ul><p>The <a href="https://owasp.org/www-project-top-10/" target="_blank" rel="noreferrer">OWASP Top 10</a> is a good starting point for understanding the most common application-layer risks. The <a href="https://owasp.org/www-project-application-security-verification-standard/" target="_blank" rel="noreferrer">OWASP Application Security Verification Standard (ASVS)</a> provides a more structured checklist for assessing the security of your application.</p><h2 id="code-reviews" tabindex="-1">Code reviews <a class="header-anchor" href="#code-reviews" aria-label="Permalink to &quot;Code reviews&quot;">​</a></h2><p>A security-focused code review looks for issues that functional review misses: input handling, authentication logic, authorisation boundaries, direct object references, and dependency risks.</p><p>Key practices:</p><ul><li>Review authentication and authorisation code on every change, not just when the feature touches security explicitly</li><li>Look for injection vectors (SQL, command, template) in any code that handles user-supplied data</li><li>Check that sensitive operations (password reset, privilege escalation, data export) require the right level of authentication</li><li>Use automated tooling (static analysis, <code>composer audit</code>) to catch known CVEs in dependencies — but treat tool output as a starting point, not a conclusion</li></ul><p>The <a href="https://owasp.org/www-project-code-review-guide/" target="_blank" rel="noreferrer">OWASP Code Review Guide</a> covers this in depth.</p><h2 id="penetration-testing" tabindex="-1">Penetration testing <a class="header-anchor" href="#penetration-testing" aria-label="Permalink to &quot;Penetration testing&quot;">​</a></h2><p>A pentest is a structured attack against your system by someone whose job is to find what you missed. It is complementary to a honeypot, not a replacement.</p><p><strong>What a pentest finds that a honeypot doesn&#39;t:</strong></p><ul><li>Vulnerabilities in your actual application logic (auth bypass, privilege escalation, IDOR)</li><li>Misconfigurations in your infrastructure (exposed admin ports, overpermissioned services)</li><li>Weaknesses in your API design</li></ul><p><strong>What a honeypot reveals that a pentest doesn&#39;t:</strong></p><ul><li>Real-world attacker behaviour against your production system</li><li>Whether automated scanners are actively targeting your stack</li><li>Credential lists that attackers are currently using in the wild</li></ul><p>Black box pentests (no prior knowledge of the system) simulate an opportunistic attacker. Grey box tests (partial knowledge) simulate a more targeted attack. Both are useful at different stages of maturity.</p><p>Consider scheduling a pentest after major architecture changes, before public launches, and at regular intervals once the system is in production. The <a href="https://owasp.org/www-project-web-security-testing-guide/" target="_blank" rel="noreferrer">OWASP Testing Guide</a> describes methodologies in detail.</p><h2 id="monitoring-and-incident-response" tabindex="-1">Monitoring and incident response <a class="header-anchor" href="#monitoring-and-incident-response" aria-label="Permalink to &quot;Monitoring and incident response&quot;">​</a></h2><p>Detection without response is just logging. When <code>AttackerAttackingEvent</code> fires, it means an automated tool submitted a known leaked password against your honeypot. That is a serious signal — not something to read in a log file the next morning.</p><p>Key practices:</p><ul><li>Route high-severity events (Attacking, campaign detection) to an alerting pipeline that pages someone in real time</li><li>Keep a runbook: what does your team do when an attacker is detected? Who is notified? What is the escalation path?</li><li>Feed honeypot events into your SIEM if you have one — correlate them with other signals (failed real logins, unusual traffic patterns)</li><li>Define what &quot;blocked&quot; means operationally: is an IP blocked at the Laravel level only, or does your infrastructure act on it too?</li></ul><h2 id="dependency-hygiene" tabindex="-1">Dependency hygiene <a class="header-anchor" href="#dependency-hygiene" aria-label="Permalink to &quot;Dependency hygiene&quot;">​</a></h2><p>Attackers scan for known CVEs before trying credentials. A vulnerable dependency advertised in a public file (a <code>composer.lock</code> checked into a public repo, or a plugin <code>readme.txt</code>) is an invitation.</p><ul><li>Run <code>composer audit</code> regularly and treat high-severity findings as blocking issues</li><li>Subscribe to security advisories for your core dependencies (Laravel, database drivers, auth packages)</li><li>Review and remove unused packages — every dependency is a potential attack surface</li></ul><p>The <a href="https://nvd.nist.gov/" target="_blank" rel="noreferrer">NIST National Vulnerability Database</a> and <a href="https://cve.mitre.org/" target="_blank" rel="noreferrer">CVE.mitre.org</a> are authoritative sources for known vulnerabilities.</p><hr><div class="tip custom-block"><p class="custom-block-title">Further reading</p><ul><li><a href="https://owasp.org/www-project-top-10/" target="_blank" rel="noreferrer">OWASP Top 10</a></li><li><a href="https://owasp.org/www-project-application-security-verification-standard/" target="_blank" rel="noreferrer">OWASP ASVS</a></li><li><a href="https://owasp.org/www-project-web-security-testing-guide/" target="_blank" rel="noreferrer">OWASP Testing Guide</a></li><li><a href="https://owasp.org/www-project-code-review-guide/" target="_blank" rel="noreferrer">OWASP Code Review Guide</a></li><li><a href="https://www.nist.gov/cyberframework" target="_blank" rel="noreferrer">NIST Cybersecurity Framework</a></li></ul></div>',31)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
